using UnityEngine;
using System.Collections;

public class CoroutineExample : MonoBehaviour
{
    void Start()
    {
        // Start coroutines
        StartCoroutine(CountdownCoroutine(5));
        StartCoroutine(FlashCoroutine(3));
        StartCoroutine(MoveCoroutine(Vector3.right, 5f, 2f));

        // Start a coroutine that runs forever
        StartCoroutine(BackgroundPulseCoroutine());
    }

    void Update()
    {
        // Start coroutines with keys
        if (Input.GetKeyDown(KeyCode.S))
        {
            StartCoroutine(ScaleCoroutine(2f, 0.5f));
        }

        if (Input.GetKeyDown(KeyCode.R))
        {
            StartCoroutine(RotateCoroutine(360f, 1f));
        }

        if (Input.GetKeyDown(KeyCode.C))
        {
            StopAllCoroutines();
            Debug.Log("All coroutines stopped!");
        }
    }

    // --- Basic Coroutines ---

    public IEnumerator CountdownCoroutine(int seconds)
    {
        Debug.Log("Countdown started!");

        for (int i = seconds; i > 0; i--)
        {
            Debug.Log(i + "...");
            yield return new WaitForSeconds(1f);
        }

        Debug.Log("GO!");
    }

    public IEnumerator FlashCoroutine(int times)
    {
        SpriteRenderer sr = GetComponent<SpriteRenderer>();
        if (sr == null) yield break;

        for (int i = 0; i < times; i++)
        {
            sr.enabled = false;
            yield return new WaitForSeconds(0.2f);
            sr.enabled = true;
            yield return new WaitForSeconds(0.2f);
        }

        Debug.Log("Flash complete!");
    }

    public IEnumerator MoveCoroutine(Vector3 direction, float distance, float duration)
    {
        Vector3 startPos = transform.position;
        Vector3 targetPos = startPos + direction * distance;
        float elapsed = 0f;

        while (elapsed < duration)
        {
            elapsed += Time.deltaTime;
            float progress = elapsed / duration;
            transform.position = Vector3.Lerp(startPos, targetPos, progress);
            yield return null;  // Wait one frame
        }

        transform.position = targetPos;
        Debug.Log("Movement complete!");
    }

    public IEnumerator ScaleCoroutine(float scale, float duration)
    {
        Vector3 startScale = transform.localScale;
        Vector3 targetScale = Vector3.one * scale;
        float elapsed = 0f;

        while (elapsed < duration)
        {
            elapsed += Time.deltaTime;
            float progress = elapsed / duration;
            transform.localScale = Vector3.Lerp(startScale, targetScale, progress);
            yield return null;
        }

        transform.localScale = targetScale;
    }

    public IEnumerator RotateCoroutine(float degrees, float duration)
    {
        Quaternion startRot = transform.rotation;
        Quaternion targetRot = startRot * Quaternion.Euler(0, 0, degrees);
        float elapsed = 0f;

        while (elapsed < duration)
        {
            elapsed += Time.deltaTime;
            float progress = elapsed / duration;
            transform.rotation = Quaternion.Slerp(startRot, targetRot, progress);
            yield return null;
        }

        transform.rotation = targetRot;
    }

    // --- Infinite Coroutine ---

    public IEnumerator BackgroundPulseCoroutine()
    {
        while (true)
        {
            transform.localScale = Vector3.one * 1.1f;
            yield return new WaitForSeconds(0.5f);
            transform.localScale = Vector3.one;
            yield return new WaitForSeconds(0.5f);
        }
    }

    // --- Coroutine with variable waiting ---

    public IEnumerator RandomWaitCoroutine()
    {
        while (true)
        {
            float waitTime = Random.Range(0.5f, 2f);
            Debug.Log("Waiting " + waitTime + " seconds...");
            yield return new WaitForSeconds(waitTime);
            Debug.Log("Done waiting!");
        }
    }

    // --- Coroutine with custom yield ---

    public IEnumerator WaitForInputCoroutine(KeyCode key)
    {
        Debug.Log("Press " + key + " to continue...");
        yield return new WaitUntil(() => Input.GetKeyDown(key));
        Debug.Log("Key pressed!");
    }
}

