using UnityEngine;
using System.Collections;

public class CoroutineError : MonoBehaviour
{
    void Start()
    {
        // Forgot to use StartCoroutine!
        CountdownCoroutine(5);  // This does nothing!
    }

    IEnumerator CountdownCoroutine(int seconds)
    {
        // Never runs because it wasn't started
        yield return null;
        Debug.Log("Countdown!");
    }
}

phase2.explanation:
You need to use `StartCoroutine()` to start a coroutine.

**The fix:**
```csharp
void Start()
{
    StartCoroutine(CountdownCoroutine(5));
}
```

**Sharp-chan says:**
"Coroutines must be started with `StartCoroutine()`."
